const data = $input.first().json;
const product = {
  name: String(data.name || '').trim().slice(0, 120),
  description: String(data.description || '').trim(),
  price: Number(data.price || 0),
  stock: Math.max(0, Number(data.stock || 0)),
  sku: String(data.sku || '').trim(),
  images: Array.isArray(data.images) ? data.images.map(String).filter(Boolean) : [],
  category: String(data.category || '').trim(),
  attributes: data.attributes || {},
  weight: data.weight ? Number(data.weight) : null,
  dimensions: data.dimensions || {}
};
return [{ json: product }];

const data = $input.first().json;
const errors = [];
if (!data.name) errors.push('name là bắt buộc');
if (!data.description) errors.push('description là bắt buộc');
if (Number(data.price) <= 0) errors.push('price phải dương');
if (Number(data.stock) < 0) errors.push('stock phải >= 0');
if (!data.sku) errors.push('sku là bắt buộc');
if (!Array.isArray(data.images) || data.images.length === 0) errors.push('images cần ít nhất 1 ảnh');
if (!data.category) errors.push('category là bắt buộc');
if (errors.length) throw new Error(`Sản phẩm không hợp lệ: ${errors.join(', ')}`);
return [{ json: data }];

const result = $input.first().json;
const webhook = $env.SOURCE_RESULT_WEBHOOK_URL;
if (webhook) {
  const res = await fetch(webhook, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(result)
  });
  if (!res.ok) console.warn('Result webhook failed', res.status);
}
return [{ json: { ...result, notified: !!webhook, saved_at: new Date().toISOString() } }];

const error = $execution.error || {};
const webhook = $env.SOURCE_RESULT_WEBHOOK_URL;
const payload = { channel: 'shopee', ok: false, error: error.message || 'Unknown error', time: new Date().toISOString() };
if (webhook) {
  await fetch(webhook, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) }).catch(() => {});
}
return [{ json: payload }];
